157→export function App() {
158→  useTheme();
159→  const [query, setQuery] = useState('');
160→  const [filterValue, setFilterValue] = useState('all');
161→  const [selectedIndex, setSelectedIndex] = useState(0);
162→  const [actionsOpen, setActionsOpen] = useState(false);
163→  const [quickLookOpen, setQuickLookOpen] = useState(false);
164→  const { toasts, show: showToast, hide: hideToast } = useToast();
165→  const { items: hudItems, show: showHUD } = useHUD();
166→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
167→  const nav = useNavigationStack<NavViewData>('Raycast');
168→  const { push } = nav;
169→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
170→    useFavorites();
171→
172→  const currentNavData = nav.currentEntry?.data;
173→  const isRoot = !currentNavData;
174→  const isFullView =
175→    currentNavData?.type === 'command' &&
176→    (getCommand(currentNavData.commandId)?.fullView ?? false);
177→
178→  const searchFilterSections: SearchDropdownSection[] = useMemo(
179→    () => [
180→      {
181→        options: [
182→          {
183→            label: 'All',
184→            value: 'all',
185→          },
186→        ],
187→      },
188→      {
189→        title: 'Types',
190→        options: [
191→          {
192→            label: 'Commands',
193→            value: 'commands',
194→          },
195→          {
196→            label: 'Applications',
197→            value: 'applications',
198→          },
199→        ],
200→      },
201→    ],
202→    [],
203→  );
204→
205→  useEffect(() => {
206→    if (nav.stackDepth === 0) {
207→      setQuery('');
208→      setFilterValue('all');
209→      setSelectedIndex(0);
210→      setActionsOpen(false);
211→      setQuickLookOpen(false);
212→    }
213→  }, [nav.stackDepth]);
214→
215→  const registrySections = useMemo(() => getSections(), []);
216→
217→  const filtered = useMemo(() => {
218→    let sections = registrySections;
219→    if (filterValue === 'commands') {
220→      sections = sections.filter(
221→        s => s.title === 'Suggestions' || s.title === 'Commands',
222→      );
223→    } else if (filterValue === 'applications') {
224→      sections = sections.filter(s => s.title === 'Applications');
225→    }
226→
227→    const result = query ? searchCommands(query) : sections;
228→
229→    const filteredResult = query
230→      ? result
231→          .map(s => {
232→            if (filterValue === 'commands') {
233→              return s.title === 'Suggestions' || s.title === 'Commands'
234→                ? s
235→                : {
236→                    ...s,
237→                    items: [],
238→                  };
239→            }
240→            if (filterValue === 'applications') {
241→              return s.title === 'Applications'
242→                ? s
243→                : {
244→                    ...s,
245→                    items: [],
246→                  };
247→            }
248→            return s;
249→          })
250→          .filter(s => s.items.length > 0)
251→      : result;
252→
253→    const allFlatItems = sections.flatMap(s => s.items);
254→    const favoriteItems = favoriteIds
255→      .map(id => allFlatItems.find(item => item.id === id))
256→      .filter((item): item is ListItemData => !!item);
257→
258→    if (query) {
259→      const lower = query.toLowerCase();
260→      const filteredFavs = favoriteItems.filter(
261→        item =>
262→          item.title.toLowerCase().includes(lower) ||
263→          item.subtitle?.toLowerCase().includes(lower),
264→      );
265→      if (filteredFavs.length > 0) {
266→        const favIds = new Set(filteredFavs.map(f => f.id));
267→        const dedupedSections = filteredResult
268→          .map(s => ({
269→            ...s,
270→            items: s.items.filter(item => !favIds.has(item.id)),
271→          }))
272→          .filter(s => s.items.length > 0);
273→        return [
274→          {
275→            title: 'Favorites',
276→            items: filteredFavs,
277→          },
278→          ...dedupedSections,
279→        ];
280→      }
281→      return filteredResult;
282→    }
283→
284→    if (favoriteItems.length > 0) {
285→      const favIds = new Set(favoriteIds);
286→      const dedupedSections = filteredResult
287→        .map(s => ({
288→          ...s,
289→          items: s.items.filter(item => !favIds.has(item.id)),
290→        }))
291→        .filter(s => s.items.length > 0);
292→      return [
293→        {
294→          title: 'Favorites',
295→          items: favoriteItems,
296→        },
297→        ...dedupedSections,
298→      ];
299→    }
300→
301→    return filteredResult;
302→  }, [
303→    query,
304→    filterValue,
305→    favoriteIds,
306→    registrySections,
307→  ]);
308→
309→  const calculatorResult = useMemo(() => {
310→    if (!isRoot || !query.trim()) return null;
311→    return evaluate(query);
312→  }, [
313→    query,
314→    isRoot,
315→  ]);
316→
317→  const allItems = useMemo(() => {
