333→    filtered,
334→    calculatorResult,
335→    query,
336→  ]);
337→
338→  const selectedItem = isRoot ? allItems[selectedIndex] : undefined;
339→
340→  const handleQueryChange = useCallback((value: string) => {
341→    setQuery(value);
342→    setSelectedIndex(0);
343→    setActionsOpen(false);
344→  }, []);
345→
346→  const handleFilterChange = useCallback((value: string) => {
347→    setFilterValue(value);
348→    setSelectedIndex(0);
349→  }, []);
350→
351→  const handleActiveIndexChange = useCallback((index: number) => {
352→    setSelectedIndex(index);
353→    setActionsOpen(false);
354→  }, []);
355→
356→  const handleDrillIn = useCallback(() => {
357→    const item = allItems[selectedIndex];
358→    if (!item) return;
359→
360→    setActionsOpen(false);
361→
362→    if (item.id === '__calculator__') {
