384→      setQuery('');
385→      showToast({
386→        style: 'success',
387→        title: `Opened ${item.title}`,
388→      });
389→    } else {
390→      showToast({
391→        style: 'success',
392→        title: `Opened ${item.title}`,
393→      });
394→    }
395→  }, [
396→    allItems,
397→    selectedIndex,
398→    showToast,
399→    showHUD,
400→    calculatorResult,
401→    push,
402→  ]);
403→
404→  const toggleActions = useCallback(() => {
405→    setActionsOpen(prev => !prev);
406→  }, []);
407→
408→  const closeActions = useCallback(() => {
409→    setActionsOpen(false);
410→  }, []);
