496→    if (settingsCmd) {
497→      const isAlreadySettings =
498→        currentNavData?.type === 'command' &&
499→        currentNavData.commandId === 'settings';
500→      if (!isAlreadySettings) {
501→        push('Settings', {
502→          type: 'command',
503→          commandId: 'settings',
504→        });
505→        setQuery('');
506→        setSelectedIndex(0);
507→        setActionsOpen(false);
508→      }
509→    }
510→  }, [
511→    currentNavData,
512→    push,
513→  ]);
514→
515→  useKeyboardShortcut(
516→    {
517→      key: ',',
518→      meta: true,
519→    },
520→    openSettings,
